typedef int (*logging_fn)(const char *format, ...);

typedef struct LOGGING {
    logging_fn debug;
    logging_fn info;
    logging_fn warning;
    logging_fn error;
    logging_fn critical;
    logging_fn fatal;

    logging_fn message;
} LOGGING;

static LOGGING logging = {
    _logging_debug,
    _logging_info,
    _logging_warning,
    _logging_error,
    _logging_critical,

    _logging_fatal,

    _logging_message
};


